mapper.select:
SELECT tm.`联单编号`, tm.`广东省联单号`, tm.`国家联单号`, tm.`产生单位`, tm.`产废单位所属市`, tm.`产废单位所属区`, tm.`产废单位所属镇`, tm.`发运人`, tm.`接收人`, tm.`接收单位`, tm.`接收单位所属省`, tm.`接收单位所属市`, tm.`接收单位所属区`, tm.`许可证编号`, tm.`接收单位处理意见`, DATE_FORMAT(tm.`接收日期`, '%Y-%m-%d') AS `接收日期`, tm.`处置方式大类`, tm.`处置方式小类`, tm.`车牌号`, tm.`承运人`, tm.`运输单位`, DATE_FORMAT(tm.`运输开始时间`, '%Y-%m-%d %H:%i:%s') AS `运输开始时间`, DATE_FORMAT(tm.`运输结束时间`, '%Y-%m-%d %H:%i:%s') AS `运输结束时间`, DATE_FORMAT(tm.`计划转移时间`, '%Y-%m-%d') AS `计划转移时间`, tm.`当前阶段`, tm.`补录类型`, tm.`是否存在重大差异`, tm.`重大差异简述`, tm.`接收企业备注`, tm.`是否作废`, tm.`PDF文件编号`, DATE_FORMAT(tm.`创建时间`, '%Y-%m-%d %H:%i:%s') AS `创建时间`, f.`文件名称` AS `文件名称`, f.`存储类型` AS `存储类型`, f.`本地存储路径` AS `本地存储路径`, f.`对象键` AS `对象键`, f.`访问URL` AS `访问URL` FROM TRANSFER_MANIFEST tm LEFT JOIN FILE f ON f.`文件编号` = tm.`PDF文件编号` AND f.`文件状态` = '正常' WHERE tm.`是否删除` = 0
AND tm.`广东省联单号` LIKE CONCAT('%', #{广东省联单号}, '%')
AND tm.`国家联单号` LIKE CONCAT('%', #{国家联单号}, '%')
AND tm.`产生单位` LIKE CONCAT('%', #{产生单位}, '%')
AND tm.`接收单位` LIKE CONCAT('%', #{接收单位}, '%')
AND tm.`车牌号` LIKE CONCAT('%', #{车牌号}, '%')
AND tm.`当前阶段` = #{当前阶段}
AND tm.`计划转移时间` >= #{计划转移开始}
AND tm.`计划转移时间` <= #{计划转移结束}
ORDER BY tm.${sortField} ${sortOrder}
ORDER BY tm.`联单编号` ASC

mapper.update:
UPDATE TRANSFER_MANIFEST SET `PDF文件编号` = CASE `联单编号`
WHEN #{item.manifestId} THEN #{item.pdfFileId}
END, `更新时间` = NOW() WHERE `联单编号` IN
#{item.manifestId}
AND `是否删除` = 0

mapper.select:
SELECT `联单编号`, `广东省联单号`, `国家联单号`, `PDF文件编号`, `是否删除` FROM TRANSFER_MANIFEST WHERE `是否删除` = 0 AND (
`广东省联单号` LIKE CONCAT('%', #{d}, '%') OR `国家联单号` LIKE CONCAT('%', #{d}, '%')
)
